/**
 * Question 42: Merge Two Sorted Linked Lists
 *
 * Problem: You are given the heads of two sorted linked lists list1 and list2.
 * Merge the two lists into one sorted list. The list should be made by splicing together 
 * the nodes of the first two lists. Return the head of the merged linked list.
 * 
 * Example 1:
 * Input: list1 = [1,2,4], list2 = [1,3,4]
 * Output: [1,1,2,3,4,4]
 * 
 * Example 2:
 * Input: list1 = [], list2 = []
 * Output: []
 *
 * Beginner Friendly Solution Approach:
 * 1. An easy beginner way is to extract every single value from both lists and just dump them into a standard Java ArrayList.
 * 2. Traverse `list1` entirely, storing its values.
 * 3. Traverse `list2` entirely, storing its values.
 * 4. Sort the ArrayList natively using `Collections.sort()`.
 * 5. Create a brand new linked list by reading the sorted values from the ArrayList successively.
 * 6. Return the head of this brand new list.
 */
import java.util.ArrayList;
import java.util.Collections;

public class Qs42_MergeSortedLinkedLists {

    // Definition for singly-linked list node
    static class ListNode {
        int val;
        ListNode next;
        ListNode(int val) { this.val = val; }
    }

    public static void main(String[] args) {
        // Construct list1: 1 -> 2 -> 4
        ListNode list1 = new ListNode(1);
        list1.next = new ListNode(2);
        list1.next.next = new ListNode(4);
        
        // Construct list2: 1 -> 3 -> 4
        ListNode list2 = new ListNode(1);
        list2.next = new ListNode(3);
        list2.next.next = new ListNode(4);
        
        ListNode merged = mergeTwoListsBeginner(list1, list2);
        
        // Print output
        System.out.print("Output: [");
        ListNode curr = merged;
        while (curr != null) {
            System.out.print(curr.val + (curr.next != null ? "," : ""));
            curr = curr.next;
        }
        System.out.println("]");
    }
    
    // O((N+M) log(N+M)) Time and O(N+M) Space explicitly smartly elegantly accurately smartly
    public static ListNode mergeTwoListsBeginner(ListNode list1, ListNode list2) {
        ArrayList<Integer> values = new ArrayList<>();
        
        ListNode current = list1;
        while (current != null) {
            values.add(current.val);
            current = current.next;
        }
        
        current = list2;
        while (current != null) {
            values.add(current.val);
            current = current.next;
        }
        
        Collections.sort(values);
        
        if (values.isEmpty()) return null;
        
        ListNode dummyHead = new ListNode(0);
        ListNode builder = dummyHead;
        
        for (int val : values) {
            builder.next = new ListNode(val);
            builder = builder.next;
        }
        
        return dummyHead.next;
    }
}

